def exersize():
    exersizes = ["Замени душ на 5 минут вместо 10","Прогулка пешком вместо поездки на одну остановку", "Закрывай кран когда чистишь зубы", "Загружай стиральную машину полностью (не по две футболки)", "После зарядки телефона выдерни провод из розети", "Не включай вытяжку без необходимости", "Положи крышку на кастрюлю при кипячении", "Стирай бельё при 30 градусах вместо 60", "Не бери лишний пакет на кассе", "Откажись от трубочки в кофейне", "Не выбрасывай батарейки весте со всеми отходаи", "Поменяй бумажные полотеца на новые" ]
